import SwiftUI
import AVFoundation

struct BarcodeScannerView: UIViewRepresentable {
    let session: AVCaptureSession
    @Binding var scannedCode: String?
    var onScan: (String) -> Void

    func makeUIView(context: Context) -> ScannerUIView {
        let view = ScannerUIView()
        view.previewLayer.session = session
        view.previewLayer.videoGravity = .resizeAspectFill

        let metadataOutput = AVCaptureMetadataOutput()
        if session.canAddOutput(metadataOutput) {
            session.addOutput(metadataOutput)
            metadataOutput.setMetadataObjectsDelegate(context.coordinator, queue: .main)
            metadataOutput.metadataObjectTypes = [.qr, .ean13, .ean8, .code128, .code39, .upce]
        }
        return view
    }

    func updateUIView(_ uiView: ScannerUIView, context: Context) {}

    func makeCoordinator() -> Coordinator {
        Coordinator(onScan: onScan)
    }

    class Coordinator: NSObject, AVCaptureMetadataOutputObjectsDelegate {
        let onScan: (String) -> Void
        private var lastScanTime: Date = .distantPast
        init(onScan: @escaping (String) -> Void) { self.onScan = onScan }
        func metadataOutput(_ output: AVCaptureMetadataOutput, didOutput objects: [AVMetadataObject], from connection: AVCaptureConnection) {
            guard Date().timeIntervalSince(lastScanTime) > 1.5,
                  let obj = objects.first as? AVMetadataMachineReadableCodeObject,
                  let value = obj.stringValue else { return }
            lastScanTime = Date()
            UIImpactFeedbackGenerator(style: .medium).impactOccurred()
            onScan(value)
        }
    }

    class ScannerUIView: UIView {
        let previewLayer = AVCaptureVideoPreviewLayer()
        override init(frame: CGRect) { super.init(frame: frame); layer.addSublayer(previewLayer) }
        required init?(coder: NSCoder) { fatalError() }
        override func layoutSubviews() { super.layoutSubviews(); previewLayer.frame = bounds }
    }
}
